  {| jl := jr g; jr := jl g; jg := fun (b : B) (a : A) => (jg g a b)^ |}

JoinRecPath
  {|
    jl := fun x : B => g (jr f x);
    jr := fun x : A => g (jl f x);
    jg := fun (b : B) (a : A) => (ap g (jg f a b))^
  |}
  (joinrecdata_fun g
